  logic [MaxLfsrDw-1:0] lfsr_periods [MaxLfsrDw+1];
  logic [MaxLfsrDw-1:0] entropy      [MaxLfsrDw+1];
  logic [MaxLfsrDw-1:0] seed         [MaxLfsrDw+1];
