   //////////////////////////////////////////////////////
   prim_lfsr #(
      .LfsrType    ( LfsrType ),
      .LfsrDw      ( k        ),
      .EntropyDw   ( k        ),
      .StateOutDw  ( k        ),
      .DefaultSeed ( k'(SEED) ),
