      .rst_ni        ( rst_n               ),
      .seed_en_i     ( seed_en[k]          ),
      .seed_i        ( seed[k][k-1:0]      ),
      .lfsr_en_i     ( lfsr_en[k]          ),
      .entropy_i     ( entropy[k][k-1:0]   ),
      .state_o       ( state_out[k][k-1:0] )
    );

